#include <iostream>

class IntBuffer {
    int  m_size;
    int* m_data;
public:
    IntBuffer(int size, const int* src)
        : m_size{size}, m_data{new int[size]} {
        for (int i = 0; i < size; ++i)
            m_data[i] = src[i];
    }

    IntBuffer(const IntBuffer& src)
        : m_size{src.m_size}, m_data{new int[src.m_size]} {
        for (int i = 0; i < m_size; ++i)
            m_data[i] = src.m_data[i];
    }

    IntBuffer& operator=(const IntBuffer& rhs) {
        if (this == &rhs) return *this;
        delete[] m_data;
        m_size = rhs.m_size;
        m_data = new int[m_size];
        for (int i = 0; i < m_size; ++i)
            m_data[i] = rhs.m_data[i];
        return *this;
    }

    ~IntBuffer() { delete[] m_data; }

    void set(int idx, int val) { m_data[idx] = val; }
    void print() const {
        for (int i = 0; i < m_size; ++i) {
            if (i > 0) std::cout << ' ';
            std::cout << m_data[i];
        }
        std::cout << '\n';
    }
};

int main() {
    int n;
    std::cin >> n;
    int* tmp = new int[n];
    for (int i = 0; i < n; ++i) std::cin >> tmp[i];
    IntBuffer A{n, tmp};
    delete[] tmp;
    IntBuffer B{A};
    for (int i = 0; i < n; ++i) B.set(i, 0);
    std::cout << "original: ";
    A.print();
    std::cout << "copy: ";
    B.print();
    return 0;
}

