#include <iostream>
#include <cstring>

class SharedString {
    char* m_buf;
public:
    SharedString(const char* s) : m_buf{new char[strlen(s) + 1]} {
        strcpy(m_buf, s);
    }

    SharedString(const SharedString& src)
        : m_buf{new char[strlen(src.m_buf) + 1]} {
        strcpy(m_buf, src.m_buf);
    }

    ~SharedString() { delete[] m_buf; }

    void assign(const char* s) {
        delete[] m_buf;
        m_buf = new char[strlen(s) + 1];
        strcpy(m_buf, s);
    }

    void print(char label) const {
        std::cout << label << ": " << m_buf << '\n';
    }
};

int main() {
    char word[32];
    std::cin >> word;
    SharedString A{word};
    SharedString B{A};
    B.assign("hello");
    A.print('A');
    B.print('B');
    return 0;
}
